var BRANDS_ALL = ["현대", "기아", "제네시스", "쉐보레", "KGM", "르노코리아", "테슬라", "벤츠", "BMW", "볼보", "아우디", "폭스바겐", "렉서스", "도요타", "BYD", "수입"];
// 표준 계약조건 옵션 (상세 바텀시트에 전체 노출, 관리자는 기본값 1개 선택)
